import{_ as l,g as o,c as i,a as t,D as a,B as n}from"./chunks/framework.BwvlL9Nv.js";const _=JSON.parse('{"title":"🗺️ 第二部分：标准工作流 (从需求到上线)","description":"","frontmatter":{},"headers":[],"relativePath":"part2.md","filePath":"part2.md","lastUpdated":1775810312000}'),s={name:"part2.md"};function e(g,r,h,d,c,p){return o(),i("div",null,[...r[0]||(r[0]=[t("h1",{id:"🗺️-第二部分-标准工作流-从需求到上线",tabindex:"-1"},[a("🗺️ 第二部分：标准工作流 (从需求到上线) "),t("a",{class:"header-anchor",href:"#🗺️-第二部分-标准工作流-从需求到上线","aria-label":'Permalink to "🗺️ 第二部分：标准工作流 (从需求到上线)"'},"​")],-1),t("h2",{id:"4.火炬",UI:"",设计全流程:"",tabindex:"-1"},[a("4. 火炬 UI 设计全流程 "),t("a",{class:"header-anchor",href:"#4.火炬","aria-label":'Permalink to "4. 火炬 UI 设计全流程{#4.火炬 UI 设计全流程}"'},"​")],-1),n('<h3 id="4.1需求评审：如何看懂PRD与反讲需求" tabindex="-1">4.1 需求评审：如何看懂PRD与反讲需求 <a class="header-anchor" href="#4.1需求评审：如何看懂PRD与反讲需求" aria-label="Permalink to &quot;4.1 需求评审：如何看懂PRD与反讲需求{#4.1需求评审：如何看懂PRD与反讲需求}&quot;">​</a></h3><ol><li><strong>接收需求</strong>：产品下发PRD（产品需求文档，在企业微信-微盘-技术部文件里查找），明确产品类型、客户需求、核心功能、主要风格、项目优先级。</li><li><strong>需求对齐</strong>：主动与产品沟通，确认需求细节（避免理解偏差），如有不合理需求应及时与产品沟通。</li><li><strong>制定设计计划与工时参考</strong>： <ul><li><strong>🟢 换皮/复用类</strong>：仅替换切图与色值，<strong>预计 1 - 1.5 个工作日</strong>。</li><li><strong>🟡 局部新增类</strong>：涉及1-2个新增复杂弹窗或游戏面板，<strong>预计 2 - 5 个工作日</strong>。</li><li><strong>🔴 全案定制类</strong>：涉及一二三级页面全设计，<strong>需提前报备组长和主管，预留 10 个工作日以上</strong>（含至少3轮评审）。</li></ul></li></ol><h3 id="4.2设计执行：自查清单（空态/极限值/权限）" tabindex="-1">4.2 设计执行：自查清单（空态/极限值/权限） <a class="header-anchor" href="#4.2设计执行：自查清单（空态/极限值/权限）" aria-label="Permalink to &quot;4.2 设计执行：自查清单（空态/极限值/权限）{#4.2设计执行：自查清单（空态/极限值/权限）}&quot;">​</a></h3><ol><li><strong>高保真设计</strong>：项目应保证美观、切图完整、质量达标、效率高。</li><li><strong>自查清单</strong>： <ul><li><strong>无障碍</strong>：对比度是否足够？字号是否清晰？</li><li><strong>组件状态</strong>：空态、加载态、错误态是否已设计？（<strong>列表为空只给白板属于不合格交付</strong>）</li><li><strong>交互规范</strong>：点击热区是否不小于44x44px？</li><li><strong>极限情况</strong>：昵称最长时如何截断？金额数字过大时如何显示？</li></ul></li><li><strong>游戏/动效设计</strong>：蓝湖中有很多游戏的种类，比如转盘、抽奖、押宝等，不同的游戏有不同的玩法，不过大致都分为首页、排行榜、规则、奖池、榜单等几个主要页面，动效一般需要设计游戏背景动效（也叫启屏动效，与游戏高度一致）和大奖动效（全屏高度，抽到价值较高礼物的时候展示，没有大奖玩法的则不需要设计，需要配套音效）</li></ol><h3 id="4.3交付物标准：切图命名规范表与图层整理要求" tabindex="-1">4.3 交付物标准：切图命名规范表与图层整理要求 <a class="header-anchor" href="#4.3交付物标准：切图命名规范表与图层整理要求" aria-label="Permalink to &quot;4.3 交付物标准：切图命名规范表与图层整理要求{#4.3交付物标准：切图命名规范表与图层整理要求}&quot;">​</a></h3><ol><li><strong>评审与迭代</strong>： <ul><li><strong>产品评审</strong>：在蓝湖中与产品经理核对产品功能清单上的内容，确保功能完整、不额外增加功能，不缺少必要功能。</li><li><strong>客户评审</strong>：下载蓝湖组合图并发送到对接群，艾特客户审查，清晰表达设计思路，认真记录评审意见（区分必改项、可选项、延后项），不纠结“审美分歧”，重点关注落地性和用户体验。</li><li><strong>方案迭代</strong>：根据评审意见修改设计稿，修改完成后同步导师/产品确认，直至通过。</li></ul></li><li><strong>交付物</strong>： <ul><li>核对最终设计稿、标注文件、切图。</li><li>若使用 Photoshop 设计，需特别注意确认切图位置（PS对蓝湖插件兼容性一般）。</li><li>若有游戏动效设计，则需要导出为svga格式文件（存好备用），然后转换为vap格式文件（尾缀为.mp4是正常的，因为vap格式是给.mp4的视频右侧加一个alpha蒙版），将转换好的vap以及给动效配的音效（.mp3文件）打成压缩包发给开发人员。</li></ul></li></ol><h3 id="4.4.走查与验收：设计还原度打分表" tabindex="-1">4.4 走查与验收：设计还原度打分表 <a class="header-anchor" href="#4.4.走查与验收：设计还原度打分表" aria-label="Permalink to &quot;4.4 走查与验收：设计还原度打分表{#4.4.走查与验收：设计还原度打分表}&quot;">​</a></h3><ol><li><strong>开发对接</strong>：解答开发人员的疑问，协助开发还原设计效果，避免因沟通偏差导致还原度不足。</li><li><strong>走查验收</strong>：开发完成后，将测试包下载到测试机中，对照设计稿进行走查，记录还原度问题，提交给测试人员或直接告知前端，跟进修复直至验收通过。</li></ol><h2 id="5.上线后复盘与沉淀" tabindex="-1">5. 上线后复盘与沉淀 <a class="header-anchor" href="#5.上线后复盘与沉淀" aria-label="Permalink to &quot;5. 上线后复盘与沉淀{#5.上线后复盘与沉淀}&quot;">​</a></h2><ul><li><strong>经验沉淀</strong>：总结本次需求的问题（如需求理解偏差、评审效率低），避免后续重复踩坑。</li><li><strong>迭代优化</strong>：根据用户反馈，与产品和开发人员同步后优化高保真设计稿，进行下一轮迭代需求。</li></ul>',10)])])}const m=l(s,[["render",e]]);export{_ as __pageData,m as default};
